{
  "path": "/orgs/{org}/copilot-spaces/{space_number}/resources",
  "method": "POST",
  "schema": {
    "type": "object",
    "required": [
      "resource_type",
      "metadata"
    ],
    "properties": {
      "resource_type": {
        "type": "string",
        "enum": [
          "repository",
          "github_file",
          "free_text",
          "github_issue",
          "github_pull_request"
        ],
        "description": "The type of resource to create."
      },
      "metadata": {
        "type": "object",
        "description": "Resource-specific metadata.",
        "additionalProperties": true
      }
    }
  }
}
